#include <sys/stat.h>
#include <unistd.h>
#include <stdio.h>

int create_dir(const char *path) {
 if (mkdir(path, 0755) == 0) {
 printf("Created: %s\n", path);
 return 0;
 } else {
 perror("mkdir failed");
 return -1;
 }
}

int main() {
 create_dir("/home");
 create_dir("/home/user");
 create_dir("/home/user/documents");
 create_dir("/home/user/documents/projects");
 return 0;
}

#include <sys/stat.h>
#include <unistd.h>
#include <stdio.h>
#include <string.h>
#include <errno.h>

int is_directory(const char *path) {
 struct stat st;
 if (stat(path, &st) == 0)
 return S_ISDIR(st.st_mode);
 return 0;
}

int safe_rmdir(const char *path) {
 char cwd[256];

 // Check if path exists
 if (access(path, F_OK) != 0) {
 fprintf(stderr, "Error: %s does not exist\n", path);
 return -1;
 }

 // Check if it's a directory
 if (!is_directory(path)) {
 fprintf(stderr, "Error: %s is not a directory\n", path);
 return -1;
 }

 // Check if it's current directory
 getcwd(cwd, sizeof(cwd));
 if (strcmp(cwd, path) == 0) {
 fprintf(stderr, "Error: Cannot remove current directory\n");
 return -1;
 }

 // Attempt removal
 if (rmdir(path) == 0) {
 printf("Successfully removed %s\n", path);
 return 0;
 } else {
 perror("rmdir failed");
 return -1;
 }
}

int main() {
 safe_rmdir("/home/user/testdir");
 return 0;
}
